<div class="page-head"><div><h1><?= e($module['name']) ?></h1><p class="muted">Operational records for <?= e($module['name']) ?>.</p></div><a class="btn light" href="<?= app_url('/'.$module['slug'].'/settings') ?>">Module Settings</a></div><div class="grid two"><div class="card"><h3>Create / Edit Data</h3><form method="post" action="<?= app_url('/'.$module['slug'].'/store') ?>"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><?php foreach($schema as $field): ?><label><?= e(ucwords(str_replace('_',' ',$field))) ?></label><input name="<?= e($field) ?>" placeholder="<?= e($field) ?>"><?php endforeach; ?><button class="btn primary">Save</button></form></div><div class="card"><h3>Workflow</h3><p class="muted">Status, audit, and approval-ready foundation for this module.</p><span class="badge info">Operational</span><span class="badge success">Settings Enabled</span><span class="badge warning">BlueHub Ready</span></div></div><div class="card"><h3>List Data</h3><div class="table-wrap"><table data-searchable><thead><tr><th>ID</th><?php foreach($schema as $field): ?><th><?= e(ucwords(str_replace('_',' ',$field))) ?></th><?php endforeach; ?><th>Status</th><th>Created</th></tr></thead><tbody><?php foreach($records as $r): $d=json_decode($r['data_json'],true)?:[]; ?><tr><td><?= e($r['id']) ?></td><?php foreach($schema as $field): ?><td><?= e($d[$field] ?? '') ?></td><?php endforeach; ?><td><span class="badge success"><?= e($r['status']) ?></span></td><td><?= e($r['created_at']) ?></td></tr><?php endforeach; ?></tbody></table></div></div>
